#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N0, P, M, B;
        scanf("%d %d %d %d", &N0, &P, &M, &B);
        double R1, R2, R3, R4;
        scanf("%lf %lf %lf %lf", &R1, &R2, &R3, &R4);
        double sum = 0;
        int N = N0;
        double RN = R4;
        for (int i = 0; i < N; i++) {
            sum += RN;
            double Rtemp = (R1 - RN - R2) / 2;
            RN = Rtemp;
            N = (P * N + B) % M;
        }
        printf("%.6f\n", sum);
    }
    return 0;
}

